.perf-panel__card-drill--visible[data-v-3fab912b]:hover {
  color: #c878c8;
}

/* =============== DRILL-DOWN MODAL =============== */
.perf-modal__backdrop[data-v-3fab912b] {
  position: fixed;
  top: 0;
  left: 0;
  right: 0;
  bottom: 0;
  background: rgba(0, 0, 0, 0.45);
  z-index: 10000;
  display: flex;
  align-items: center;
  justify-content: center;
  padding: 24px;
  animation: perf-fade-in-3fab912b 0.15s ease;
}
@keyframes perf-fade-in-3fab912b {
from {
    opacity: 0;
}
to {
    opacity: 1;
}
}
.perf-modal[data-v-3fab912b] {
  background: #fff;
  border-radius: 16px;
  box-shadow: 0 20px 60px rgba(0, 0, 0, 0.2);
  width: 100%;
  max-width: 780px;
  max-height: 80vh;
  display: flex;
  flex-direction: column;
  animation: perf-slide-up-3fab912b 0.2s ease;
}
@keyframes perf-slide-up-3fab912b {
from {
