    transform: translateY(12px);
}
to {
    opacity: 1;
    transform: translateY(0);
}
}
.perf-modal__header[data-v-3fab912b] {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 20px 24px;
  border-bottom: 1px solid #eef1f5;
  flex-shrink: 0;
}
.perf-modal__title[data-v-3fab912b] {
  font-size: 18px;
  font-weight: 700;
  color: #1a1a2e;
  margin: 0;
  padding: 0;
  border: none;
}
.perf-modal__close[data-v-3fab912b] {
  background: none;
  border: none;
  font-size: 24px;
  color: #6b7280;
  cursor: pointer;
  width: 36px;
  height: 36px;
  border-radius: 50%;
  display: flex;
  align-items: center;
  justify-content: center;
  transition: background 0.15s, color 0.15s;
  flex-shrink: 0;
}
.perf-modal__close[data-v-3fab912b]:hover {
  background: #f0f1f5;
  color: #1a1a2e;
}
.perf-modal__body[data-v-3fab912b] {
  padding: 16px 24px 24px;
  overflow-y: auto;
  flex: 1;
}
.perf-modal__body[data-v-3fab912b]::-webkit-scrollbar {
  width: 5px;
}
.perf-modal__body[data-v-3fab912b]::-webkit-scrollbar-thumb {
  background: #d1d5db;
  border-radius: 3px;
}

/* Project Row */
.perf-modal__project[data-v-3fab912b] {
  margin-bottom: 12px;
  border: 1px solid #eef1f5;
  border-radius: 10px;
  overflow: hidden;
}
.perf-modal__project-header[data-v-3fab912b] {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
  cursor: pointer;
  transition: background 0.15s;
