}
.perf-modal__project-header[data-v-3fab912b]:hover {
  background: #fafbfd;
}
.perf-modal__project-name[data-v-3fab912b] {
  font-size: 14px;
  font-weight: 600;
  color: #1a1a2e;
  flex: 1;
  min-width: 0;
  overflow: hidden;
