  white-space: nowrap;
}
.perf-modal__goto-btn[data-v-3fab912b] {
  font-size: 11px;
  font-weight: 600;
  padding: 3px 10px;
  border-radius: 12px;
  border: 1px solid #c878c8;
  background: #fff;
  color: #a855a8;
  cursor: pointer;
  white-space: nowrap;
  transition: background 0.15s, color 0.15s;
}
.perf-modal__goto-btn[data-v-3fab912b]:hover {
  background: #c878c8;
  color: #fff;
}
.perf-modal__project-stats[data-v-3fab912b] {
  display: flex;
  align-items: center;
  gap: 6px;
  flex-shrink: 0;
  flex-wrap: wrap;
}
.perf-modal__chevron[data-v-3fab912b] {
