  color: #1a1a2e;
  border-bottom: 1px solid #f3f4f6;
  vertical-align: middle;
}
.perf-modal__task-table tbody tr:last-child td[data-v-3fab912b] {
  border-bottom: none;
}
.perf-modal__task-table tbody tr[data-v-3fab912b]:hover {
  background: #f5f6fa;
}

/* Status and Category pills */
.perf-modal__status[data-v-3fab912b],
.perf-modal__category[data-v-3fab912b] {
  font-size: 11px;
  font-weight: 600;
  padding: 2px 8px;
  border-radius: 10px;
  white-space: nowrap;
}
.perf-modal__status--done[data-v-3fab912b] {
  background: #d4edda;
  color: #166534;
}
.perf-modal__status--open[data-v-3fab912b] {
  background: #e8f0fe;
  color: #1e4a8a;
}
.perf-modal__status--archived[data-v-3fab912b] {
  background: #f0f1f5;
  color: #6b7280;
}
.perf-modal__category--on-time[data-v-3fab912b] {
  background: #d4edda;
  color: #166534;
}
.perf-modal__category--delayed[data-v-3fab912b] {
  background: #fef3cd;
  color: #92400e;
}
.perf-modal__category--blocked[data-v-3fab912b] {
  background: #fde8e8;
  color: #b91c1c;
}
.perf-modal__stack-badge[data-v-3fab912b] {
  font-size: 11px;
  background: #f0f1f5;
  color: #6b7280;
  padding: 2px 6px;
  border-radius: 4px;
  white-space: nowrap;
}
.perf-modal__assignee-badge[data-v-3fab912b] {
  display: inline-block;
  font-size: 11px;
  background: #eef2ff;
  color: #4f46e5;
  padding: 2px 6px;
  border-radius: 4px;
  white-space: nowrap;
  margin: 1px 3px 1px 0;
}
.perf-modal__assignee-none[data-v-3fab912b] {
  font-size: 11px;
  color: #9ca3af;
  font-style: italic;
}

/* Empty states */
.perf-modal__empty[data-v-3fab912b] {
