  padding: 32px 16px;
  color: #9ca3af;
  font-size: 14px;
}
.perf-modal__empty-inline[data-v-3fab912b] {
  padding: 12px 8px;
  color: #9ca3af;
  font-size: 13px;
  font-style: italic;
}

/* Transition */
.perf-modal-expand-enter-active[data-v-3fab912b],
.perf-modal-expand-leave-active[data-v-3fab912b] {
  transition: all 0.2s ease;
  overflow: hidden;
}
.perf-modal-expand-enter[data-v-3fab912b],
.perf-modal-expand-leave-to[data-v-3fab912b] {
  opacity: 0;
  max-height: 0;
  padding-top: 0;
  padding-bottom: 0;
}

