@media (max-width: 1024px) {
.perf-panel__top-grid[data-v-3fab912b],
  .perf-panel__bottom-grid[data-v-3fab912b] {
    grid-template-columns: 1fr;
}
.perf-modal[data-v-3fab912b] {
    max-width: 100%;
    max-height: 90vh;
}
}
