AAA;AACA;AAEA;EACA,cAAA;AACA;;AAEA,qDAAA;AAEA;EACA,eAAA;EACA,MAAA;EACA,OAAA;EACA,QAAA;EACA,SAAA;EACA,+BAAA;EACA,cAAA;EACA,aAAA;EACA,mBAAA;EACA,uBAAA;EACA,aAAA;EACA,2CAAA;AACA;AAEA;AACA;IACA,UAAA;AACA;AACA;IACA,UAAA;AACA;AACA;AAEA;EACA,gBAAA;EACA,mBAAA;EACA,0CAAA;EACA,WAAA;EACA,gBAAA;EACA,gBAAA;EACA,aAAA;EACA,sBAAA;EACA,2CAAA;AACA;AAEA;AACA;IACA,UAAA;IACA,2BAAA;AACA;AACA;IACA,UAAA;IACA,wBAAA;AACA;AACA;AAEA;EACA,aAAA;EACA,mBAAA;EACA,8BAAA;EACA,kBAAA;EACA,gCAAA;EACA,cAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,cAAA;EACA,SAAA;EACA,UAAA;EACA,YAAA;AACA;AAEA;EACA,gBAAA;EACA,YAAA;EACA,eAAA;EACA,cAAA;EACA,eAAA;EACA,WAAA;EACA,YAAA;EACA,kBAAA;EACA,aAAA;EACA,mBAAA;EACA,uBAAA;EACA,yCAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,uBAAA;EACA,gBAAA;EACA,OAAA;AACA;AAEA;EACA,UAAA;AACA;AAEA;EACA,mBAAA;EACA,kBAAA;AACA;;AAEA,gBAAA;AACA;EACA,mBAAA;EACA,yBAAA;EACA,mBAAA;EACA,gBAAA;AACA;AAEA;EACA,aAAA;EACA,mBAAA;EACA,8BAAA;EACA,kBAAA;EACA,eAAA;EACA,4BAAA;EACA,SAAA;AACA;AAEA;EACA,mBAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,cAAA;EACA,OAAA;EACA,YAAA;EACA,gBAAA;EACA,uBAAA;EACA,mBAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,iBAAA;EACA,mBAAA;EACA,yBAAA;EACA,gBAAA;EACA,cAAA;EACA,eAAA;EACA,mBAAA;EACA,yCAAA;AACA;AAEA;EACA,mBAAA;EACA,WAAA;AACA;AAEA;EACA,aAAA;EACA,mBAAA;EACA,QAAA;EACA,cAAA;EACA,eAAA;AACA;AAEA;EACA,eAAA;EACA,gBAAA;EACA,cAAA;EACA,+BAAA;EACA,oBAAA;EACA,gBAAA;AACA;AAEA;EACA,wBAAA;AACA;;AAEA,WAAA;AACA;EACA,eAAA;EACA,gBAAA;EACA,gBAAA;EACA,mBAAA;EACA,mBAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,WAAA;AACA;;AAEA,aAAA;AACA;EACA,aAAA;EACA,mBAAA;EACA,QAAA;EACA,iBAAA;EACA,6BAAA;EACA,kBAAA;AACA;AAEA;EACA,eAAA;EACA,WAAA;EACA,gBAAA;AACA;AAEA;EACA,eAAA;EACA,iBAAA;EACA,mBAAA;EACA,sBAAA;EACA,gBAAA;EACA,WAAA;EACA,eAAA;EACA,0BAAA;AACA;AAEA;EACA,kBAAA;AACA;AAEA;EACA,mBAAA;EACA,WAAA;EACA,qBAAA;AACA;;AAEA,uBAAA;AACA;EACA,qBAAA;EACA,gBAAA;EACA,mBAAA;EACA,eAAA;EACA,gBAAA;EACA,mBAAA;EACA,WAAA;EACA,mBAAA;AACA;;AAEA,0BAAA;AACA;EACA,WAAA;EACA,mBAAA;AACA;AAEA;EACA,YAAA;EACA,oDAAA;EACA,2BAAA;AACA;;AAEA,eAAA;AACA;EACA,oBAAA;EACA,mBAAA;AACA;AAEA;EACA,WAAA;EACA,yBAAA;EACA,eAAA;AACA;AAEA;EACA,gBAAA;EACA,eAAA;EACA,gBAAA;EACA,cAAA;EACA,yBAAA;EACA,sBAAA;EACA,qBAAA;EACA,gCAAA;AACA;AAEA;EACA,YAAA;EACA,cAAA;EACA,gCAAA;EACA,sBAAA;AACA;AAEA;EACA,mBAAA;AACA;AAEA;EACA,mBAAA;AACA;;AAEA,8BAAA;AACA;;EAEA,eAAA;EACA,gBAAA;EACA,gBAAA;EACA,mBAAA;EACA,mBAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,mBAAA;EACA,cAAA;AACA;AAEA;EACA,eAAA;EACA,mBAAA;EACA,cAAA;EACA,gBAAA;EACA,kBAAA;EACA,mBAAA;AACA;AAEA;EACA,qBAAA;EACA,eAAA;EACA,mBAAA;EACA,cAAA;EACA,gBAAA;EACA,kBAAA;EACA,mBAAA;EACA,qBAAA;AACA;AAEA;EACA,eAAA;EACA,cAAA;EACA,kBAAA;AACA;;AAEA,iBAAA;AACA;EACA,kBAAA;EACA,kBAAA;EACA,cAAA;EACA,eAAA;AACA;AAEA;EACA,iBAAA;EACA,cAAA;EACA,eAAA;EACA,kBAAA;AACA;;AAEA,eAAA;AACA;;EAEA,yBAAA;EACA,gBAAA;AACA;AAEA;;EAEA,UAAA;EACA,aAAA;EACA,cAAA;EACA,iBAAA;AACA;;AAEA,eAAA;AACA;AACA;;IAEA,0BAAA;AACA;AAEA;IACA,eAAA;IACA,gBAAA;AACA;AACA","sourcesContent":["<template>\n  <component\n    :is=\"embedded ? 'div' : 'section'\"\n    :class=\"['perf-panel', { 'perf-panel--embedded': embedded }]\"\n  >\n    <!-- HEADER (standalone only) -->\n    <div\n      v-if=\"!embedded\"\n      class=\"perf-panel__header\"\n      @click=\"collapsed = !collapsed\"\n    >\n      <h3 class=\"perf-panel__title\">\n        <svg\n          xmlns=\"http://www.w3.org/2000/svg\"\n          width=\"18\"\n          height=\"18\"\n          viewBox=\"0 0 24 24\"\n          fill=\"none\"\n          stroke=\"currentColor\"\n          stroke-width=\"2\"\n          stroke-linecap=\"round\"\n          stroke-linejoin=\"round\"\n        >\n          <line x1=\"18\" y1=\"20\" x2=\"18\" y2=\"10\" />\n          <line x1=\"12\" y1=\"20\" x2=\"12\" y2=\"4\" />\n          <line x1=\"6\" y1=\"20\" x2=\"6\" y2=\"14\" />\n        </svg>\n        Project Performance Analytics\n      </h3>\n      <svg\n        xmlns=\"http://www.w3.org/2000/svg\"\n        width=\"18\"\n        height=\"18\"\n        viewBox=\"0 0 24 24\"\n        fill=\"none\"\n        stroke=\"currentColor\"\n        stroke-width=\"2\"\n        stroke-linecap=\"round\"\n        stroke-linejoin=\"round\"\n        class=\"perf-panel__chevron\"\n        :class=\"{ 'perf-panel__chevron--rotated': collapsed }\"\n      >\n        <polyline points=\"18 15 12 9 6 15\" />\n      </svg>\n    </div>\n\n    <div v-show=\"embedded || !collapsed\">\n      <!-- Filters Row -->\n      <div class=\"perf-panel__date-filter-row\">\n        <div class=\"perf-panel__filters-bar\">\n          <div class=\"perf-panel__date-filter-inner\">\n            <svg\n              xmlns=\"http://www.w3.org/2000/svg\"\n              width=\"14\"\n              height=\"14\"\n              viewBox=\"0 0 24 24\"\n              fill=\"none\"\n              stroke=\"currentColor\"\n              stroke-width=\"2\"\n              stroke-linecap=\"round\"\n              stroke-linejoin=\"round\"\n              class=\"perf-panel__date-icon\"\n            >\n              <rect x=\"3\" y=\"4\" width=\"18\" height=\"18\" rx=\"2\" ry=\"2\" />\n              <line x1=\"16\" y1=\"2\" x2=\"16\" y2=\"6\" />\n              <line x1=\"8\" y1=\"2\" x2=\"8\" y2=\"6\" />\n              <line x1=\"3\" y1=\"10\" x2=\"21\" y2=\"10\" />\n            </svg>\n            <div\n              class=\"perf-panel__date-range\"\n              @click=\"showDatePicker = !showDatePicker\"\n            >\n              <span class=\"perf-panel__date-range-value\">{{\n                perfDateFrom || \"Start date\"\n              }}</span>\n              <span class=\"perf-panel__date-range-arrow\">→</span>\n              <span class=\"perf-panel__date-range-value\">{{\n                perfDateTo || \"End date\"\n              }}</span>\n            </div>\n            <button\n              v-if=\"perfDateFrom || perfDateTo\"\n              class=\"perf-panel__date-range-clear\"\n              title=\"Clear dates\"\n              @click.stop=\"clearPerfDates\"\n            >\n              ✕\n            </button>\n          </div>\n          <div class=\"perf-panel__completion-filter\">\n            <svg\n              xmlns=\"http://www.w3.org/2000/svg\"\n              width=\"14\"\n              height=\"14\"\n              viewBox=\"0 0 24 24\"\n              fill=\"none\"\n              stroke=\"currentColor\"\n              stroke-width=\"2\"\n              stroke-linecap=\"round\"\n              stroke-linejoin=\"round\"\n              class=\"perf-panel__filter-icon\"\n            >\n              <polyline points=\"22 12 18 12 15 21 9 3 6 12 2 12\" />\n            </svg>\n            <span\n              class=\"perf-panel__cr-badge\"\n              :class=\"{ 'perf-panel__cr-badge--active': completionRateFilter === '' }\"\n              @click=\"completionRateFilter = ''\"\n            >All</span>\n            <span\n              class=\"perf-panel__cr-badge perf-panel__cr-badge--red\"\n              :class=\"{ 'perf-panel__cr-badge--active': completionRateFilter === '0-25' }\"\n              @click=\"completionRateFilter = '0-25'\"\n            >0–25%</span>\n            <span\n              class=\"perf-panel__cr-badge perf-panel__cr-badge--orange\"\n              :class=\"{ 'perf-panel__cr-badge--active': completionRateFilter === '25-50' }\"\n              @click=\"completionRateFilter = '25-50'\"\n            >25–50%</span>\n            <span\n              class=\"perf-panel__cr-badge perf-panel__cr-badge--blue\"\n              :class=\"{ 'perf-panel__cr-badge--active': completionRateFilter === '50-75' }\"\n              @click=\"completionRateFilter = '50-75'\"\n            >50–75%</span>\n            <span\n              class=\"perf-panel__cr-badge perf-panel__cr-badge--green\"\n              :class=\"{ 'perf-panel__cr-badge--active': completionRateFilter === '75-100' }\"\n              @click=\"completionRateFilter = '75-100'\"\n            >75–100%</span>\n          </div>\n        </div>\n        <div\n          v-if=\"showDatePicker\"\n          v-click-outside=\"closePerfDatePicker\"\n          class=\"perf-panel__date-picker-dropdown\"\n        >\n          <div class=\"perf-panel__date-picker-months\">\n            <div class=\"perf-panel__date-picker-month\">\n              <div class=\"perf-panel__date-picker-header\">\n                <button\n                  class=\"perf-panel__date-picker-nav\"\n                  @click.stop=\"shiftPerfCalendar(-1)\"\n                >\n                  ‹\n                </button>\n                <span class=\"perf-panel__date-picker-title\">{{\n                  perfCalendarLabel(0)\n                }}</span>\n                <span></span>\n              </div>\n              <div class=\"perf-panel__date-picker-grid\">\n                <span\n                  v-for=\"d in ['Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa', 'Su']\"\n                  :key=\"d\"\n                  class=\"perf-panel__date-picker-dow\"\n                  >{{ d }}</span\n                >\n                <span\n                  v-for=\"(cell, ci) in perfCalendarCells(0)\"\n                  :key=\"'PL' + ci\"\n                  :class=\"perfDateCellClass(cell)\"\n                  @click.stop=\"cell.date && pickPerfDate(cell.date)\"\n                  >{{ cell.day }}</span\n                >\n              </div>\n            </div>\n            <div class=\"perf-panel__date-picker-month\">\n              <div class=\"perf-panel__date-picker-header\">\n                <span></span>\n                <span class=\"perf-panel__date-picker-title\">{{\n                  perfCalendarLabel(1)\n                }}</span>\n                <button\n                  class=\"perf-panel__date-picker-nav\"\n                  @click.stop=\"shiftPerfCalendar(1)\"\n                >\n                  ›\n                </button>\n              </div>\n              <div class=\"perf-panel__date-picker-grid\">\n                <span\n                  v-for=\"d in ['Mo', 'Tu', 'We', 'Th', 'Fr', 'Sa', 'Su']\"\n                  :key=\"d\"\n                  class=\"perf-panel__date-picker-dow\"\n                  >{{ d }}</span\n                >\n                <span\n                  v-for=\"(cell, ci) in perfCalendarCells(1)\"\n                  :key=\"'PR' + ci\"\n                  :class=\"perfDateCellClass(cell)\"\n                  @click.stop=\"cell.date && pickPerfDate(cell.date)\"\n                  >{{ cell.day }}</span\n                >\n              </div>\n            </div>\n          </div>\n          <div class=\"perf-panel__date-picker-footer\">\n            <button\n              class=\"perf-panel__date-picker-btn\"\n              @click.stop=\"\n                perfDateFrom = '';\n                perfDateTo = '';\n                perfDateStep = 'from';\n              \"\n            >\n              Clear\n            </button>\n            <button\n              class=\"perf-panel__date-picker-btn perf-panel__date-picker-btn--apply\"\n              @click.stop=\"showDatePicker = false\"\n            >\n              Apply\n            </button>\n          </div>\n        </div>\n      </div>\n\n      <!-- TOP ROW: Progress + Productivity -->\n      <div\n        :class=\"[\n          'perf-panel__top-grid',\n          { 'perf-panel__top-grid--single': !showMemberPerformance },\n        ]\"\n      >\n        <!-- Project Progress Comparison -->\n        <div\n          class=\"perf-panel__card perf-panel__card--clickable\"\n          @click=\"openModal('progress')\"\n        >\n          <div class=\"perf-panel__card-header-row\">\n            <h3 class=\"perf-panel__card-title\">\n              Project Progress<br />Comparison\n            </h3>\n            <span class=\"perf-panel__card-drill\" title=\"Click for details\">\n              <svg\n                xmlns=\"http://www.w3.org/2000/svg\"\n                width=\"16\"\n                height=\"16\"\n                viewBox=\"0 0 24 24\"\n                fill=\"none\"\n                stroke=\"currentColor\"\n                stroke-width=\"2\"\n                stroke-linecap=\"round\"\n                stroke-linejoin=\"round\"\n              >\n                <polyline points=\"15 3 21 3 21 9\" />\n                <line x1=\"10\" y1=\"14\" x2=\"21\" y2=\"3\" />\n                <path\n                  d=\"M21 14v5a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V7a2 2 0 0 1 2-2h5\"\n                />\n              </svg>\n            </span>\n          </div>\n          <div class=\"perf-panel__card-title-underline\"></div>\n          <div class=\"perf-panel__bar-list\">\n            <div\n              v-for=\"(item, idx) in previewProjectProgress\"\n              :key=\"'prog-' + idx\"\n              class=\"perf-panel__bar-item\"\n            >\n              <div class=\"perf-panel__bar-row\">\n                <span class=\"perf-panel__bar-label\">{{ item.name }}</span>\n                <span class=\"perf-panel__bar-value\">{{ item.progress }}%</span>\n              </div>\n              <div class=\"perf-panel__bar-track\">\n                <div\n                  class=\"perf-panel__bar-fill\"\n                  :style=\"{ width: item.progress + '%' }\"\n                ></div>\n              </div>\n            </div>\n          </div>\n          <div\n            v-if=\"crFilteredProjectProgress.length > progressPreviewLimit\"\n            class=\"perf-panel__bar-hint\"\n          >\n            Showing {{ previewProjectProgress.length }} of\n            {{ crFilteredProjectProgress.length }} projects (click for full\n            details)\n          </div>\n        </div>\n\n        <!-- Member Performance -->\n        <div\n          v-if=\"showMemberPerformance\"\n          class=\"perf-panel__card perf-panel__card--clickable\"\n          @click=\"openModal('member')\"\n        >\n          <div class=\"perf-panel__card-header-row\">\n            <h3 class=\"perf-panel__card-title\">Member<br />Performance</h3>\n            <span class=\"perf-panel__card-drill\" title=\"Click for details\">\n              <svg\n                xmlns=\"http://www.w3.org/2000/svg\"\n                width=\"16\"\n                height=\"16\"\n                viewBox=\"0 0 24 24\"\n                fill=\"none\"\n                stroke=\"currentColor\"\n                stroke-width=\"2\"\n                stroke-linecap=\"round\"\n                stroke-linejoin=\"round\"\n              >\n                <polyline points=\"15 3 21 3 21 9\" />\n                <line x1=\"10\" y1=\"14\" x2=\"21\" y2=\"3\" />\n                <path\n                  d=\"M21 14v5a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V7a2 2 0 0 1 2-2h5\"\n                />\n              </svg>\n            </span>\n          </div>\n          <div class=\"perf-panel__card-title-underline\"></div>\n          <p class=\"perf-panel__card-desc\">\n            Tasks completed per member vs assigned tasks\n          </p>\n          <div class=\"perf-panel__member-list\">\n            <div\n              v-for=\"(item, idx) in previewMemberPerformance\"\n              :key=\"'mem-' + idx\"\n              class=\"perf-panel__member-item\"\n            >\n              <div class=\"perf-panel__member-row\">\n                <div class=\"perf-panel__member-info\">\n                  <span class=\"perf-panel__member-avatar\">{{\n                    item.name.charAt(0).toUpperCase()\n                  }}</span>\n                  <span class=\"perf-panel__bar-label\">{{ item.name }}</span>\n                </div>\n                <span class=\"perf-panel__member-stats\">\n                  <span class=\"perf-panel__member-count\"\n                    >{{ item.done }}/{{ item.total }}</span\n                  >\n                  <span class=\"perf-panel__bar-value\"\n            