ss=\"perf-modal__sort-label\">Completion Rate:</span>\n              <button\n                class=\"perf-modal__sort-btn perf-modal__sort-btn--active\"\n                @click=\"\n                  completionSortBy =\n                    completionSortBy === 'desc' ? 'asc' : 'desc'\n                \"\n              >\n                {{\n                  completionSortBy === \"desc\"\n                    ? \"High \\u2192 Low\"\n                    : \"Low \\u2192 High\"\n                }}\n              </button>\n            </div>\n            <div\n              v-for=\"proj in sortedCompletionDetails\"\n              :key=\"'mc-' + proj.name\"\n              class=\"perf-modal__project\"\n            >\n              <div\n                class=\"perf-modal__project-header\"\n                @click=\"toggleProject('completion', proj.name)\"\n              >\n                <span class=\"perf-modal__project-name\">{{ proj.name }}</span>\n                <div class=\"perf-modal__project-stats\">\n                  <button\n                    class=\"perf-modal__goto-btn\"\n                    title=\"Open in Per Project Details\"\n                    @click.stop=\"goToProjectDetails(proj)\"\n                  >\n                    &#8594; Details\n                  </button>\n                  <span class=\"perf-modal__badge perf-modal__badge--info\">\n                    {{ proj.completed }}/{{ proj.total_tasks }} completed\n                  </span>\n                  <span\n                    class=\"perf-modal__chevron\"\n                    :class=\"{\n                      'perf-modal__chevron--open': isProjectOpen(\n                        'completion',\n                        proj.name,\n                      ),\n                    }\"\n                    >&#8250;</span\n                  >\n                </div>\n              </div>\n              <transition name=\"perf-modal-expand\">\n                <div\n                  v-if=\"isProjectOpen('completion', proj.name)\"\n                  class=\"perf-modal__task-table-wrap\"\n                >\n                  <div\n                    v-if=\"proj.tasks.length === 0\"\n                    class=\"perf-modal__empty-inline\"\n                  >\n                    No completed tasks yet\n                  </div>\n                  <table v-else class=\"perf-modal__task-table\">\n                    <thead>\n                      <tr>\n                        <th>Task</th>\n                        <th>Stack</th>\n                        <th>Completed</th>\n                        <th>Due Date</th>\n                        <th>Opened</th>\n                      </tr>\n                    </thead>\n                    <tbody>\n                      <tr v-for=\"(task, ti) in proj.tasks\" :key=\"'mct-' + ti\">\n                        <td>{{ task.title }}</td>\n                        <td>\n                          <span class=\"perf-modal__stack-badge\">{{\n                            task.stack\n                          }}</span>\n                        </td>\n                        <td>{{ task.completed_at }}</td>\n                        <td>{{ task.due || \"\\u2014\" }}</td>\n                        <td>\n                          <span\n                            v-if=\"task.created_at\"\n                            class=\"perf-modal__age-badge\"\n                            :title=\"formatDateShort(task.created_at)\"\n                            >{{ taskAge(task.created_at) }}</span\n                          >\n                          <span v-else>—</span>\n                        </td>\n                      </tr>\n                    </tbody>\n                  </table>\n                </div>\n              </transition>\n            </div>\n            <div\n              v-if=\"sortedCompletionDetails.length === 0\"\n              class=\"perf-modal__empty\"\n            >\n              No completion data available\n            </div>\n          </template>\n        </div>\n      </div>\n    </div>\n  </component>\n</template>\n\n<script>\nimport DonutChart from \"./DonutChart.vue\";\nimport BarChart from \"./BarChart.vue\";\nimport AreaChart from \"./AreaChart.vue\";\nimport ProjectDetailsPanel from \"./ProjectDetailsPanel.vue\";\n\nexport default {\n  name: \"ProjectPerformancePanel\",\n  components: {\n    DonutChart,\n    BarChart,\n    AreaChart,\n    ProjectDetailsPanel,\n  },\n  directives: {\n    \"click-outside\": {\n      bind: function (el, binding) {\n        el.__clickOutsideHandler = function (e) {\n          if (!el.contains(e.target)) {\n            binding.value(e);\n          }\n        };\n        document.addEventListener(\"pointerdown\", el.__clickOutsideHandler);\n      },\n      unbind: function (el) {\n        document.removeEventListener(\"pointerdown\", el.__clickOutsideHandler);\n        delete el.__clickOutsideHandler;\n      },\n    },\n  },\n  props: {\n    embedded: {\n      type: Boolean,\n      default: false,\n    },\n    projectProgress: {\n      type: Array,\n      required: true,\n    },\n    memberPerformance: {\n      type: Array,\n      required: true,\n    },\n    showMemberPerformance: {\n      type: Boolean,\n      default: true,\n    },\n    taskDelayProjects: {\n      type: Array,\n      required: true,\n    },\n    taskCompletionProjects: {\n      type: Array,\n      required: true,\n    },\n    performanceDetails: {\n      type: Object,\n      default: function () {\n        return {\n          progressDetails: [],\n          memberDetails: [],\n          delayDetails: [],\n          completionDetails: [],\n        };\n      },\n    },\n    projectDetails: {\n      type: Array,\n      default: function () {\n        return [];\n      },\n    },\n    showTeamWorkload: {\n      type: Boolean,\n      default: true,\n    },\n    showAssignees: {\n      type: Boolean,\n      default: true,\n    },\n  },\n  data: function () {\n    return {\n      collapsed: true,\n      delayIndex: 0,\n      completionIndex: 0,\n      modal: null,\n      expandedProjects: {},\n      delaySortBy: \"latest\",\n      progressSortBy: \"desc\",\n      completionSortBy: \"desc\",\n      delaySearch: \"\",\n      completionSearch: \"\",\n      delayStatusFilter: \"\",\n      completionStatusFilter: \"\",\n      completionRateFilter: \"\",\n      delayChartMode: \"donut\",\n      delayChartRenderKey: 0,\n      // Date range filter\n      perfDateFrom: \"\",\n      perfDateTo: \"\",\n      showDatePicker: false,\n      perfDateStep: \"from\",\n      perfCalendarBase: new Date(),\n    };\n  },\n  computed: {\n    progressPreviewLimit: function () {\n      return 5;\n    },\n    memberPreviewLimit: function () {\n      return 5;\n    },\n    hasDateFilter: function () {\n      return !!(this.perfDateFrom || this.perfDateTo);\n    },\n    /* ── Date-filtered card data (re-aggregated from detail tasks) ── */\n    effectiveProjectProgress: function () {\n      if (!this.hasDateFilter) return this.projectProgress || [];\n      var from = this.perfDateFrom;\n      var to = this.perfDateTo;\n      var list = this.details.progressDetails || [];\n      var result = [];\n      for (var i = 0; i < list.length; i++) {\n        var proj = list[i];\n        var total = 0;\n        var done = 0;\n        for (var j = 0; j < (proj.tasks || []).length; j++) {\n          var t = proj.tasks[j];\n          var ca = (t.created_at || \"\").substring(0, 10);\n          if (from && ca < from) continue;\n          if (to && ca > to) continue;\n          total++;\n          if (t.status === \"done\") done++;\n        }\n        result.push({\n          name: proj.name,\n          progress: total > 0 ? Math.round((done / total) * 100) : 0,\n        });\n      }\n      return result;\n    },\n    effectiveMemberPerformance: function () {\n      if (!this.hasDateFilter) return this.memberPerformance || [];\n      var from = this.perfDateFrom;\n      var to = this.perfDateTo;\n      var list = this.details.memberDetails || [];\n      var result = [];\n      for (var i = 0; i < list.length; i++) {\n        var member = list[i];\n        var total = 0;\n        var done = 0;\n        for (var j = 0; j < (member.tasks || []).length; j++) {\n          var t = member.tasks[j];\n          var ca = (t.created_at || \"\").substring(0, 10);\n          if (from && ca < from) continue;\n          if (to && ca > to) continue;\n          total++;\n          if (t.status === \"done\") done++;\n        }\n        if (total > 0) {\n          result.push({\n            name: member.name,\n            total: total,\n            done: done,\n            progress: Math.round((done / total) * 100),\n          });\n        }\n      }\n      if (result.length === 0) {\n        result.push({ name: \"No Assignments\", total: 0, done: 0, progress: 0 });\n      }\n      return result;\n    },\n    effectiveDelayProjects: function () {\n      if (!this.hasDateFilter) return this.taskDelayProjects || [];\n      var from = this.perfDateFrom;\n      var to = this.perfDateTo;\n      var list = this.details.delayDetails || [];\n      var result = [];\n      for (var i = 0; i < list.length; i++) {\n        var proj = list[i];\n        var onTime = 0;\n        var delayed = 0;\n        var blocked = 0;\n        for (var j = 0; j < (proj.tasks || []).length; j++) {\n          var t = proj.tasks[j];\n          var ca = (t.createdAt || \"\").substring(0, 10);\n          if (from && ca < from) continue;\n          if (to && ca > to) continue;\n          if (t.category === \"delayed\") delayed++;\n          else if (t.category === \"blocked\") blocked++;\n          else onTime++;\n        }\n        var total = onTime + delayed + blocked;\n        result.push({\n          name: proj.name,\n          status: proj.status || \"\",\n          chart: {\n            labels: [\"On-time Tasks\", \"Delayed Tasks\", \"Blocked Tasks\"],\n            data: [\n              total > 0 ? Math.round((onTime / total) * 100) : 0,\n              total > 0 ? Math.round((delayed / total) * 100) : 0,\n              total > 0 ? Math.round((blocked / total) * 100) : 0,\n            ],\n            colors: [\"#2ec4b6\", \"#f4a261\", \"#e63946\"],\n          },\n        });\n      }\n      return result;\n    },\n    effectiveCompletionProjects: function () {\n      if (!this.hasDateFilter) return this.taskCompletionProjects || [];\n      var from = this.perfDateFrom;\n      var to = this.perfDateTo;\n      var list = this.details.completionDetails || [];\n      var result = [];\n      for (var i = 0; i < list.length; i++) {\n        var proj = list[i];\n        var completedDates = [];\n        for (var j = 0; j < (proj.tasks || []).length; j++) {\n          var t = proj.tasks[j];\n          var ca = (t.completed_at || \"\").substring(0, 10);\n          if (from && ca < from) continue;\n          if (to && ca > to) continue;\n          completedDates.push(new Date(t.completed_at));\n        }\n        if (completedDates.length === 0) {\n          result.push({\n            name: proj.name,\n            status: proj.status || \"\",\n            weeks: [\"Week 1\", \"Week 2\", \"Week 3\", \"Week 4\", \"Week 5\", \"Week 6\"],\n            data: [0, 0, 0, 0, 0, 0],\n          });\n          continue;\n        }\n        var now = new Date();\n        var weekLabels = [];\n        var weekCounts = [];\n        for (var w = 5; w >= 0; w--) {\n          var weekStart = new Date(now);\n          weekStart.setDate(weekStart.getDate() - w * 7);\n          var day = weekStart.getDay();\n          var diff = day === 0 ? -6 : 1 - day;\n          weekStart.setDate(weekStart.getDate() + diff);\n          weekStart.setHours(0, 0, 0, 0);\n          var weekEnd = new Date(weekStart);\n          weekEnd.setDate(weekEnd.getDate() + 6);\n          weekEnd.setHours(23, 59, 59, 999);\n          var months = [\n            \"Jan\",\n            \"Feb\",\n            \"Mar\",\n            \"Apr\",\n            \"May\",\n            \"Jun\",\n            \"Jul\",\n            \"Aug\",\n            \"Sep\",\n            \"Oct\",\n            \"Nov\",\n            \"Dec\",\n          ];\n          weekLabels.push(\n            months[weekStart.getMonth()] +\n              \" \" +\n              (weekStart.getDate() < 10 ? \"0\" : \"\") +\n              weekStart.getDate(),\n          );\n          var count = 0;\n          for (var k = 0; k < completedDates.length; k++) {\n            if (completedDates[k] >= weekStart && completedDates[k] <= weekEnd)\n              count++;\n          }\n          weekCounts.push(count);\n        }\n        result.push({\n          name: proj.name,\n          status: proj.status || \"\",\n          weeks: weekLabels,\n          data: weekCounts,\n        });\n      }\n      return result;\n    },\n    hasCompletionRateFilter: function () {\n      return !!this.completionRateFilter;\n    },\n    crFilteredProjectProgress: function () {\n      var list = this.effectiveProjectProgress;\n      if (!this.hasCompletionRateFilter) return list;\n      var result = [];\n      for (var i = 0; i < list.length; i++) {\n        if (this.passesCompletionFilter(list[i].progress)) {\n          result.push(list[i]);\n        }\n      }\n      return result;\n    },\n    completionRateAllowedNames: function () {\n      if (!this.hasCompletionRateFilter) return null;\n      var allowed = {};\n      var list = this.effectiveProjectProgress;\n      for (var i = 0; i < list.length; i++) {\n        if (this.passesCompletionFilter(list[i].progress)) {\n          allowed[list[i].name] = true;\n        }\n      }\n      return allowed;\n    },\n    previewProjectProgress: function () {\n      return this.crFilteredProjectProgress\n        .slice()\n        .sort(function (a, b) {\n          return (b.progress || 0) - (a.progress || 0);\n        })\n        .slice(0, this.progressPreviewLimit);\n    },\n    previewMemberPerformance: function () {\n      return this.effectiveMemberPerformance\n        .slice()\n        .sort(function (a, b) {\n          var progressDiff = (b.progress || 0) - (a.progress || 0);\n          if (progressDiff !== 0) {\n            return progressDiff;\n          }\n          return (b.done || 0) - (a.done || 0);\n        })\n        .slice(0, this.memberPreviewLimit);\n    },\n    filteredDelayProjects: function () {\n      var q = (this.delaySearch || \"\").toLowerCase();\n      var statusFilter = this.delayStatusFilter;\n      var allowed = this.completionRateAllowedNames;\n      var result = [];\n      for (var i = 0; i < this.effectiveDelayProjects.length; i++) {\n        var proj = this.effectiveDelayProjects[i];\n        if (q && proj.name.toLowerCase().indexOf(q) === -1) {\n          continue;\n        }\n        if (statusFilter && proj.status !== statusFilter) {\n          continue;\n        }\n        if (allowed && !allowed[proj.name]) {\n          continue;\n        }\n        result.push({ name: proj.name, originalIndex: i });\n      }\n      return result;\n    },\n    filteredCompletionProjects: function () {\n      var q = (this.completionSearch || \"\").toLowerCase();\n      var statusFilter = this.completionStatusFilter;\n      var allowed = this.completionRateAllowedNames;\n      var result = [];\n      for (var i = 0; i < this.effectiveCompletionProjects.length; i++) {\n        var proj = this.effectiveCompletionProjects[i];\n        if (q && proj.name.toLowerCase().indexOf(q) === -1) {\n          continue;\n        }\n        if (statusFilter && proj.status !== statusFilter) {\n          continue;\n        }\n        if (allowed && !allowed[proj.name]) {\n          continue;\n        }\n        result.push({ name: proj.name, originalIndex: i });\n      }\n      return result;\n    },\n    activeDelayProject: function () {\n      return (\n        this.effectiveDelayProjects[this.delayIndex] || {\n          name: \"\",\n          chart: {\n            labels: [],\n            data: [0, 0, 0],\n            colors: [\"#2ec4b6\", \"#f4a261\", \"#e63946\"],\n          },\n        }\n      );\n    },\n    activeDelayBarChart: function () {\n      var colors = [\"#2ec4b6\", \"#f4a261\", \"#e63946\"];\n      var labels = [\"On-time\", \"Delayed\", \"Blocked\"];\n      var empty = { labels: labels, data: [0, 0, 0], colors: colors };\n      var activeProj = this.effectiveDelayProjects[this.delayIndex];\n      if (!activeProj) return empty;\n      var list = this.details.delayDetails || [];\n      var projDetail = null;\n      for (var i = 0; i < list.length; i++) {\n        if (list[i].name === activeProj.name) {\n          projDetail = list[i];\n          break;\n        }\n      }\n      if (!projDetail) return empty;\n      var tasks = projDetail.tasks || [];\n      var from = this.hasDateFilter ? this.perfDateFrom : \"\";\n      var to = this.hasDateFilter ? this.perfDateTo : \"\";\n      var onTime = 0;\n      var delayed = 0;\n      var blocked = 0;\n      for (var j = 0; j < tasks.length; j++) {\n        var t = tasks[j];\n        if (from || to) {\n          var ca = (t.createdAt || \"\").substring(0, 10);\n          if (from && ca < from) continue;\n          if (to && ca > to) continue;\n        }\n        if (t.category === \"delayed\") delayed++;\n        else if (t.category === \"blocked\") blocked++;\n        else onTime++;\n      }\n      return { labels: labels, data: [onTime, delayed, blocked], colors: colors };\n    },\n    activeCompletionProject: function () {\n      return (\n        this.effectiveCompletionProjects[this.completionIndex] || {\n          name: \"\",\n          weeks: [],\n          data: [],\n        }\n      );\n    },\n    details: function () {\n      return (\n        this.performanceDetails || {\n          progressDetails: [],\n          memberDetails: [],\n          delayDetails: [],\n          completionDetails: [],\n        }\n      );\n    },\n    dateFilteredProgressDetails: function () {\n      var list = this.details.progressDetails || [];\n      if (!this.hasDateFilter) return list;\n      var from = this.perfDateFrom;\n      var to = this.perfDateTo;\n      var result = [];\n      for (var i = 0; i < list.length; i++) {\n        var proj = list[i];\n        var tasks = [];\n        var total = 0;\n        var done = 0;\n        for (var j = 0; j < (proj.tasks || []).length; j++) {\n          var t = proj.tasks[j];\n          var ca = (t.created_at || \"\").substring(0, 10);\n          if (from && ca < from) continue;\n          if (to && ca > to) continue;\n          tasks.push(t);\n          total++;\n          if (t.status === \"done\") done++;\n        }\n        result.push({\n          name: proj.name,\n          id: proj.id,\n          total: total,\n          done: done,\n          progress: total > 0 ? Math.round((done / total) * 100) : 0,\n          tasks: tasks,\n        });\n      }\n      return result;\n    },\n    dateFilteredMemberDetails: function () {\n      var list = this.details.memberDetails || [];\n      if (!this.hasDateFilter) return list;\n      var from = this.perfDateFrom;\n      var to = this.perfDateTo;\n      var result = [];\n      for (var i = 0; i < list.length; i++) {\n        var mem = list[i];\n        var tasks = [];\n        var total = 0;\n        var done = 0;\n        for (var j = 0; j < (mem.tasks || []).length; j++) {\n          var t = mem.tasks[j];\n          var ca = (t.created_at || \"\").substring(0, 10);\n          if (from && ca < from) continue;\n          if (to && ca > to) continue;\n          tasks.push(t);\n          total++;\n          if (t.status === \"done\") done++;\n        }\n        if (total > 0) {\n          result.push({\n            name: mem.name,\n            total: total,\n            done: done,\n            progress: Math.round((done / total) * 100),\n            tasks: tasks,\n          });\n        }\n      }\n      return result;\n    },\n    dateFilteredDelayDetails: function () {\n      var list = this.details.delayDetails || [];\n      if (!this.hasDateFilter) return list;\n      var from = this.perfDateFrom;\n      var to = this.perfDateTo;\n      var result = [];\n      for (var i = 0; i < list.length; i++) {\n        var proj = list[i];\n        var tasks = [];\n        var totalAge = 0;\n        var ageCount = 0;\n        var now = new Date();\n        var latestOpened = null;\n        var oldestOpened = null;\n        for (var j = 0; j < (proj.tasks || []).length; j++) {\n          var t = proj.tasks[j];\n          var ca = (t.createdAt || \"\").substring(0, 10);\n          if (from && ca < from) continue;\n          if (to && ca > to) continue;\n          tasks.push(t);\n          if (t.createdAt) {\n            var created = new Date(t.createdAt);\n            var age = Math.floor((now - created) / (1000 * 60 * 60 * 24));\n            totalAge += age;\n            ageCount++;\n            if (!latestOpened || t.createdAt > latestOpened)\n              latestOpened = t.createdAt;\n            if (!oldestOpened || t.createdAt < oldestOpened)\n              oldestOpened = t.createdAt;\n          }\n        }\n        result.push({\n          name: proj.name,\n          id: proj.id,\n          status: proj.status || \"\",\n          tasks: tasks,\n          avgDaysActive: ageCount > 0 ? Math.round(totalAge / ageCount) : 0,\n          latestTaskOpened: latestOpened,\n          oldestTaskOpened: oldestOpened,\n        });\n      }\n      return result;\n    },\n    dateFilteredCompletionDetails: function () {\n      var list = this.details.completionDetails || [];\n      if (!this.hasDateFilter) return list;\n      var from = this.perfDateFrom;\n      var to = this.perfDateTo;\n      var result = [];\n      for (var i = 0; i < list.length; i++) {\n        var proj = list[i];\n        var tasks = [];\n        for (var j = 0; j < (proj.tasks || []).length; j++) {\n          var t = proj.tasks[j];\n          var ca = (t.completed_at || \"\").substring(0, 10);\n          if (from && ca < from) continue;\n          if (to && ca > to) continue;\n          tasks.push(t);\n        }\n        result.push({\n          name: proj.name,\n          id: proj.id,\n          status: proj.status || \"\",\n          total_tasks: proj.total_tasks,\n          completed: tasks.length,\n          tasks: tasks,\n        });\n      }\n      return result;\n    },\n    sortedProgressDetails: function () {\n      var list = this.dateFilteredProgressDetails.slice();\n      if (this.hasCompletionRateFilter) {\n        var self = this;\n        list = list.filter(function (p) {\n          return self.passesCompletionFilter(p.progress);\n        });\n      }\n      if (this.progressSortBy === \"asc\") {\n        list.sort(function (a, b) {\n          return a.progress - b.progress;\n        });\n      } else {\n        list.sort(function (a, b) {\n          return b.progress - a.progress;\n        });\n      }\n      return list;\n    },\n    sortedDelayDetails: function () {\n      var list = this.dateFilteredDelayDetails.slice();\n      var allowed = this.completionRateAllowedNames;\n      if (allowed) {\n        list = list.filter(function (p) {\n          return !!allowed[p.name];\n        });\n      }\n      var sortBy = this.delaySortBy;\n      if (sortBy === \"latest\") {\n        list.sort(function (a, b) {\n          var da = a.latestTaskOpened\n            ? new Date(a.latestTaskOpened).getTime()\n            : 0;\n          var db = b.latestTaskOpened\n            ? new Date(b.latestTaskOpened).getTime()\n            : 0;\n          return db - da;\n        });\n      } else if (sortBy === \"oldest\") {\n        list.sort(function (a, b) {\n          var da = a.oldestTaskOpened\n            ? new Date(a.oldestTaskOpened).getTime()\n            : Infinity;\n          var db = b.oldestTaskOpened\n            ? new Date(b.oldestTaskOpened).getTime()\n            : Infinity;\n          return da - db;\n        });\n      } else {\n        list.sort(function (a, b) {\n          return a.name.localeCompare(b.name);\n        });\n      }\n      return list;\n    },\n    sortedCompletionDetails: function () {\n      var list = this.dateFilteredCompletionDetails.slice();\n      var allowed = this.completionRateAllowedNames;\n      if (allowed) {\n        list = list.filter(function (p) {\n          return !!allowed[p.name];\n        });\n      }\n      var sortBy = this.completionSortBy;\n      if (sortBy === \"asc\") {\n        list.sort(function (a, b) {\n          var rateA = a.total_tasks > 0 ? a.completed / a.total_tasks : 0;\n          var rateB = b.total_tasks > 0 ? b.completed / b.total_tasks : 0;\n          return rateA - rateB;\n        });\n      } else {\n        list.sort(function (a, b) {\n          var rateA = a.total_tasks > 0 ? a.completed / a.total_tasks : 0;\n          var rateB = b.total_tasks > 0 ? b.completed / b.total_tasks : 0;\n          return rateB - rateA;\n        });\n      }\n      return list;\n    },\n    modalTitle: function () {\n      var titles = {\n        progress: \"Project Progress \\u2014 Task Details\",\n        member: \"Member Performance \\u2014 Task Details\",\n        delay: \"Task Delay Overview \\u2014 Task Details\",\n        completion: \"Task Completion \\u2014 Completed Tasks\",\n      };\n      return titles[this.modal] || \"\";\n    },\n  },\n  watch: {\n    collapsed: function (isCollapsed) {\n      var self = this;\n      if (!isCollapsed) {\n        this.$nextTick(function () {\n          self.delayChartRenderKey++;\n        });\n      }\n    },\n    filteredDelayProjects: function (list) {\n      if (list.length > 0) {\n        var found = false;\n        for (var i = 0; i < list.length; i++) {\n          if (list[i].originalIndex === this.delayIndex) {\n            found = true;\n            break;\n          }\n        }\n        if (!found) {\n          this.delayIndex = list[0].originalIndex;\n        }\n      }\n    },\n    filteredCompletionProjects: function (list) {\n      if (list.length > 0) {\n        var found = false;\n        for (var i = 0; i < list.length; i++) {\n          if (list[i].originalIndex === this.completionIndex) {\n            found = true;\n            break;\n          }\n        }\n        if (!found) {\n          this.completionIndex = list[0].originalIndex;\n        }\n      }\n    },\n    effectiveDelayProjects: function (list) {\n      if (this.delayIndex >= list.length) {\n        this.delayIndex = 0;\n      }\n    },\n    effectiveCompletionProjects: function (list) {\n      if (this.completionIndex >= list.length) {\n        this.completionIndex = 0;\n      }\n    },\n  },\n  methods: {\n    prevDelayProject: function () {\n      this.delayIndex =\n        (this.delayIndex - 1 + this.effectiveDelayProjects.length) %\n        this.effectiveDelayProjects.length;\n    },\n    nextDelayProject: function () {\n      this.delayIndex =\n        (this.delayIndex + 1) % this.effectiveDelayProjects.length;\n    },\n    prevCompletionProject: function () {\n      this.completionIndex =\n        (this.completionIndex - 1 + this.effectiveCompletionProjects.length) %\n        this.effectiveCompletionProjects.length;\n    },\n    nextCompletionProject: function () {\n      this.completionIndex =\n        (this.completionIndex + 1) % this.effectiveCompletionProjects.length;\n    },\n    openModal: function (type) {\n      this.modal = type;\n      this.expandedProjects = {};\n      document.body.style.overflow = \"hidden\";\n    },\n    closeModal: function () {\n      this.modal = null;\n      this.expandedProjects = {};\n      document.body.style.overflow = \"\";\n    },\n    toggleProject: function (section, name) {\n      var key = section + \":\" + name;\n      this.$set(this.expandedProjects, key, !this.expandedProjects[key]);\n    },\n    isProjectOpen: function (section, name) {\n      return !!this.expandedProjects[section + \"